import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { toast } from 'react-toastify';
import { useAuth } from '../../context/AuthContext';

const SEMESTERS = [1,2,3,4,5,6,7,8];

async function loadXLSX() { if(window.XLSX)return window.XLSX; await new Promise((res,rej)=>{const s=document.createElement('script');s.src='https://cdnjs.cloudflare.com/ajax/libs/xlsx/0.18.5/xlsx.full.min.js';s.onload=res;s.onerror=rej;document.head.appendChild(s);}); return window.XLSX; }
async function exportExcel(sheets,filename) { const XLSX=await loadXLSX();const wb=XLSX.utils.book_new();sheets.forEach(({name,data})=>{const ws=XLSX.utils.aoa_to_sheet(data);ws['!cols']=data[0]?.map((_,ci)=>({wch:Math.max(...data.map(r=>String(r[ci]??'').length),10)}));XLSX.utils.book_append_sheet(wb,ws,name.slice(0,31));});XLSX.writeFile(wb,filename); }
async function loadJsPDF() { if(window.jspdf)return window.jspdf.jsPDF; await new Promise((res,rej)=>{const s=document.createElement('script');s.src='https://cdnjs.cloudflare.com/ajax/libs/jspdf/2.5.1/jspdf.umd.min.js';s.onload=res;s.onerror=rej;document.head.appendChild(s);}); await new Promise((res,rej)=>{const s=document.createElement('script');s.src='https://cdnjs.cloudflare.com/ajax/libs/jspdf-autotable/3.5.31/jspdf.plugin.autotable.min.js';s.onload=res;s.onerror=rej;document.head.appendChild(s);}); return window.jspdf.jsPDF; }
async function exportPDF(title,subtitle,head,body,filename) { const JsPDF=await loadJsPDF();const doc=new JsPDF({orientation:'landscape'});doc.setFontSize(16);doc.setFont('helvetica','bold');doc.text('VEMU Institute of Technology',doc.internal.pageSize.width/2,15,{align:'center'});doc.setFontSize(12);doc.setFont('helvetica','normal');doc.text(title,doc.internal.pageSize.width/2,23,{align:'center'});doc.setFontSize(10);doc.text(subtitle,doc.internal.pageSize.width/2,30,{align:'center'});doc.text(`Generated: ${new Date().toLocaleDateString('en-IN')}`,doc.internal.pageSize.width/2,36,{align:'center'});doc.autoTable({startY:42,head:[head],body,styles:{fontSize:8,cellPadding:2},headStyles:{fillColor:[26,86,219],textColor:255,fontStyle:'bold'},alternateRowStyles:{fillColor:[241,245,249]},margin:{left:10,right:10}});doc.save(filename); }

export default function FacultyReports() {
  const { user }  = useAuth();
  const [loading, setLoading] = useState(false);
  const [selSem,  setSelSem]  = useState('');
  const [subjects,setSubjects]= useState([]);
  const [selSubj, setSelSubj] = useState('');
  const [selMid,  setSelMid]  = useState('');

  useEffect(() => {
    if (!selSem) { setSubjects([]); setSelSubj(''); return; }
    axios.get('/api/faculty/subjects', { params:{ semester:selSem } })
      .then(r => { setSubjects(r.data.subjects||[]); setSelSubj(''); });
  }, [selSem]);

  const wrap = async fn => { setLoading(true); try { await fn(); } catch(e) { toast.error('Export failed: '+e.message); } finally { setLoading(false); } };

  const excelClassMarks = () => wrap(async () => {
    if (!selSem) return toast.error('Select semester');
    const marksR = await axios.get('/api/faculty/marks', { params:{ semester:selSem, ...(selSubj?{subjectId:selSubj}:{}), ...(selMid?{midExam:selMid}:{}) } });
    // Filter out promoted students - only include students currently in this semester
    marksR.data.marks = marksR.data.marks.filter(m => m.student?.semester === Number(selSem));
    const marks = marksR.data.marks;
    const mid1 = marks.filter(m=>m.midExam==='Mid-1');
    const mid2 = marks.filter(m=>m.midExam==='Mid-2');
    const sheets = [];

    if (!selMid || selMid==='Mid-1') sheets.push({ name:`Sem${selSem} Mid-1`, data:[
      [`Semester ${selSem} — Mid-1 Marks — ${user?.name}`],[`Generated: ${new Date().toLocaleDateString('en-IN')}`],[],
      ['#','Student','Roll No','Section','Subject','Asgn/5','SHA/10','Best Q1/Q2','Best Q3/Q4','Best Q5/Q6','Q-Half/15','Total/30','Status'],
      ...mid1.map((m,i)=>[i+1,m.student?.name||'—',m.student?.rollNumber||'—',m.student?.section||'—',m.subject?.name||'—',m.assignmentMarks,m.shaMarks,m.bestQ1Q2,m.bestQ3Q4,m.bestQ5Q6,m.questionHalf,m.totalMarks,m.status])
    ]});

    if (!selMid || selMid==='Mid-2') sheets.push({ name:`Sem${selSem} Mid-2`, data:[
      [`Semester ${selSem} — Mid-2 Marks — ${user?.name}`],[`Generated: ${new Date().toLocaleDateString('en-IN')}`],[],
      ['#','Student','Roll No','Section','Subject','Asgn/5','SHA/10','Best Q1/Q2','Best Q3/Q4','Best Q5/Q6','Q-Half/15','Total/30','Status'],
      ...mid2.map((m,i)=>[i+1,m.student?.name||'—',m.student?.rollNumber||'—',m.student?.section||'—',m.subject?.name||'—',m.assignmentMarks,m.shaMarks,m.bestQ1Q2,m.bestQ3Q4,m.bestQ5Q6,m.questionHalf,m.totalMarks,m.status])
    ]});

    if (!sheets.length) return toast.error('No marks found');
    const subj = subjects.find(s=>s._id===selSubj);
    await exportExcel(sheets, `VEMU_Sem${selSem}${subj?'_'+subj.code:''}_Marks.xlsx`);
    toast.success('Class marks Excel downloaded!');
  });

  const pdfClassMarks = () => wrap(async () => {
    if (!selSem) return toast.error('Select semester');
    const marksR = await axios.get('/api/faculty/marks', { params:{ semester:selSem, ...(selSubj?{subjectId:selSubj}:{}), ...(selMid?{midExam:selMid}:{}) } });
    // Filter out promoted students - only include students currently in this semester
    marksR.data.marks = marksR.data.marks.filter(m => m.student?.semester === Number(selSem));
    const subj = subjects.find(s=>s._id===selSubj);
    await exportPDF(
      `Semester ${selSem}${subj?' — '+subj.name:''} Marks Report`,
      `Faculty: ${user?.name}`,
      ['#','Student','Roll No','Sec','Subject','Exam','Asgn/5','SHA/10','Q-Half/15','Total/30','Status'],
      marksR.data.marks.map((m,i)=>[i+1,m.student?.name||'—',m.student?.rollNumber||'—',m.student?.section||'—',m.subject?.name||'—',m.midExam,m.assignmentMarks,m.shaMarks,m.questionHalf,m.totalMarks,m.status]),
      `VEMU_Sem${selSem}${subj?'_'+subj.code:''}_Marks.pdf`);
    toast.success('PDF downloaded!');
  });

  return (
    <div>
      <div className="page-header">
        <div><div className="page-title">📋 Reports</div><div className="page-subtitle">Generate class-level marks reports for your subjects</div></div>
      </div>

      <div className="card" style={{ marginBottom:20 }}>
        <div className="card-header"><span className="card-title">📚 Class-wise Marks Report</span></div>
        <div className="card-body">
          <p style={{ color:'var(--text-muted)',fontSize:13,marginBottom:14 }}>Filter by semester, subject and exam to generate your class marks report with full question breakdown</p>
          <div style={{ display:'flex', gap:10, flexWrap:'wrap', marginBottom:16 }}>
            <div>
              <label style={{ fontSize:12, fontWeight:600, display:'block', marginBottom:4 }}>Semester *</label>
              <select className="form-select" style={{ width:160 }} value={selSem} onChange={e=>setSelSem(e.target.value)}>
                <option value="">Select Semester</option>
                {SEMESTERS.map(s=><option key={s} value={s}>Semester {s}</option>)}
              </select>
            </div>
            <div>
              <label style={{ fontSize:12, fontWeight:600, display:'block', marginBottom:4 }}>Subject (optional)</label>
              <select className="form-select" style={{ width:220 }} value={selSubj} onChange={e=>setSelSubj(e.target.value)} disabled={!selSem}>
                <option value="">All Assigned Subjects</option>
                {subjects.map(s=><option key={s._id} value={s._id}>{s.name} ({s.code})</option>)}
              </select>
            </div>
            <div>
              <label style={{ fontSize:12, fontWeight:600, display:'block', marginBottom:4 }}>Mid Exam (optional)</label>
              <select className="form-select" style={{ width:150 }} value={selMid} onChange={e=>setSelMid(e.target.value)}>
                <option value="">Both Mids</option>
                <option value="Mid-1">Mid-1 Only</option>
                <option value="Mid-2">Mid-2 Only</option>
              </select>
            </div>
          </div>
          <div style={{ display:'flex', gap:10, flexWrap:'wrap' }}>
            <button className="btn btn-success" onClick={excelClassMarks} disabled={loading||!selSem}>📊 Download Excel (with Q breakdown)</button>
            <button className="btn btn-danger"  onClick={pdfClassMarks}   disabled={loading||!selSem}>📄 Download PDF</button>
          </div>
        </div>
      </div>

      {loading && <div style={{ textAlign:'center',padding:20,color:'var(--text-muted)',fontSize:13 }}>⏳ Generating report...</div>}
    </div>
  );
}
